	&lt;li&gt;&lt;span id=&quot;docs-internal-guid-1ff545e9-7fff-ec4d-f5ec-fb697ed7cb46&quot;&gt;&lt;span style=&quot;  font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;&quot;&gt;खेल का मैदान - &lt;/span&gt;&lt;span style=&quot;  font-variant-numeric: normal; font-variant-east-asian: normal; vertical-align: baseline; white-space: pre-wrap;&quot;&gt;क्रीडाक्षेत्रम्&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;स्पष्टीकरण &lt;/strong&gt;-&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;वाक्य&lt;/strong&gt; - &amp;quot;आश्रमे &lt;strong&gt;वटाश्वत्थनिम्बाशोकाम्रामलक&lt;/strong&gt;-वृक्षाः आसन्।&amp;quot;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अर्थ&lt;/strong&gt; - आश्रम में &lt;strong&gt;&amp;#39;वट&amp;#39;, &amp;#39;अश्वत्थ&amp;#39;, &amp;#39;निम्ब&amp;#39;, &amp;#39;अशोक&amp;#39;, &amp;#39;आम्र&amp;#39;, &amp;#39;अमलक (आँवला)&lt;/strong&gt;&amp;#39; ये&amp;nbsp;वृक्ष थे।&lt;/li&gt;
	&lt;li&gt;इस तरह वाक्य से स्पष्ट है कि आश्रम में &lt;strong&gt;छः (6) वृक्ष&lt;/strong&gt; थे।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/important-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Important Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;इस वाक्य में उल्लेखित वृक्षों के नाम -&lt;/p&gt;

&lt;ol&gt;
	&lt;li&gt;वट - बरगद&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;अश्वत्थ - पीपल&lt;/li&gt;
	&lt;li&gt;निम्ब - नीम&lt;/li&gt;
	&lt;li&gt;अशोक - पवित्र माना गया वृक्ष&lt;/li&gt;
	&lt;li&gt;आम्र - आम&lt;/li&gt;
	&lt;li&gt;अमलक - आँवला&lt;/li&gt;
&lt;/ol&gt;

&lt;p&gt;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;अतः स्पष्ट है कि&amp;nbsp;इस वाक्य में &amp;#39;&lt;strong&gt;छह&lt;/strong&gt;&amp;#39; वृक्षों के नाम है।&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;स्पष्टीकरण -&amp;nbsp;&lt;/strong&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;u&gt;लूता&lt;/u&gt; यह&amp;nbsp;विजातीय पद है ।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;विजातीय का शाब्दिक अर्थ अलग पहचान (जाति) से होता है। लूता का शाब्दिक अर्थ मकड़ी होता है। बाकी विकल्पों&amp;nbsp;के अर्थ के अनुसार वह मसाले में परिगणित होते है ।&amp;nbsp;&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information/Other Options&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;लवङ्गम्&lt;/span&gt; का शाब्दिक अर्थ - लौंग है। |&lt;/li&gt;
	&lt;li&gt;तथा एला&amp;nbsp;का शाब्दिक अर्थ - इलायची है ।&amp;nbsp;&amp;nbsp;&amp;nbsp;&lt;/li&gt;
	&lt;li&gt;मधुरिका&amp;nbsp;का शाब्दिक अर्थ - सौंफ&amp;nbsp;हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;strong&gt;स्पष्टीकरण -&lt;/strong&gt;&amp;nbsp;&lt;/p&gt;

&lt;ul&gt;
